    // encountered so far while scanning from right to left (i.e., counts for j > i).
    long long total_even_right = 0;
    long long total_odd_right = 0;

    // Iterate from the last element backwards to the first element
    for (int i = n - 1; i >= 0; --i) {
        long long current_num = nums[i];

        // Determine parity: 0 for even, 1 for odd
        bool is_odd = (current_num % 2 != 0);

        // Calculate the score for index i based on the counts of elements to the right (j > i)
        if (is_odd) {
            // If nums[i] is odd, the score is the count of even numbers to the right.
            answer[i] = total_even_right;
