            // If nums[i] is even, the score is the count of odd numbers to the right.
            answer[i] = total_odd_right;
        }

        // Update the suffix counts to include the current element nums[i] for the next iteration (i-1)
        if (is_odd) {
            total_odd_right++;
        } else {
            total_even_right++;
        }
    }

    return answer;
}

