using namespace std;

/**
 * @brief Calculates the score for each element in the array.
 * 
 * The score of index i is the count of indices j such that i < j < n and nums[i] and nums[j] have different parities.
 * 
 * @param nums The input array of integers.
 * @return std::vector<long long> The array where answer[i] is the score of index i.
 */
std::vector<long long> solve(std::vector<long long> nums) {
    int n = nums.size();
    if (n <= 1) {
        return std::vector<long long>(n, 0);
    }

    std::vector<long long> answer(n);

    // Iterate through each index i from 0 to n-2 (since i < j < n requires at least one j)
    for (int i = 0; i < n - 1; ++i) {
        long long count = 0;
        // Determine the parity of nums[i]
        // parity is 0 if even, 1 if odd
        int parity_i = nums[i] % 2;

        // Count the number of suitable j's where i < j < n
        for (int j = i + 1; j < n; ++j) {
            // Determine the parity of nums[j]
            int parity_j = nums[j] % 2;

            // Check if parities are different
            if (parity_i != parity_j) {
                count++;
            }
        }
        answer[i] = count;
    }

    // The last element (index n-1) always has a score of 0 because there is no j such that n-1 < j < n.
    answer[n - 1] = 0;

    return answer;
}
